// query — строка от агента, напр.: "violationDate=2026-01-15; discoveryDate=2026-01-20"
// Сроки — внутренний буфер Контура (НЕ дословно ТК РФ):
//   нарушение: +5 мес 15 дн;  обнаружение: +20 дн.
// ТК РФ baseline: 6 мес / 30 дн. Уточнять у Касмыниной О.
const text = String(query || '');
const dates = text.match(/\d{4}-\d{2}-\d{2}/g) || [];
const violationStr = dates[0];
const discoveryStr = dates[1] || dates[0];
if (!violationStr) {
  return JSON.stringify({ error: 'Не нашёл дат в формате ГГГГ-ММ-ДД', received: text });
}
const now = new Date();
const violationDate = new Date(violationStr);
const discoveryDate = new Date(discoveryStr);
const vDeadline = new Date(violationDate);
vDeadline.setMonth(vDeadline.getMonth() + 5);
vDeadline.setDate(vDeadline.getDate() + 15);
const dDeadline = new Date(discoveryDate);
dDeadline.setDate(dDeadline.getDate() + 20);
const expiredByViolation = now >= vDeadline;
const expiredByDiscovery = now >= dDeadline;
const fmt = (d) => d.toISOString().split('T')[0];
return JSON.stringify({
  isExpired: expiredByViolation || expiredByDiscovery,
  expiredReason: expiredByViolation ? 'violation_date' : (expiredByDiscovery ? 'discovery_date' : null),
  violationDeadline: fmt(vDeadline),
  discoveryDeadline: fmt(dDeadline),
  today: fmt(now)
});
